package com.example.remider.presentation

import android.annotation.SuppressLint
import android.app.AlarmManager
import android.app.PendingIntent
import android.content.Context
import android.content.Intent
import androidx.compose.ui.platform.LocalContext
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.remider.data.RemiderState
import com.example.remider.domain.RemindersEntity
import com.example.remider.domain.RemindersRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import java.util.Calendar
import kotlin.String

class MainViewModel(
    private val repository: RemindersRepository
): ViewModel() {
    private val _state = MutableStateFlow(RemiderState())
    val state = _state.asStateFlow()
    val calendar = Calendar.getInstance().apply {
        set(Calendar.HOUR_OF_DAY, 10)
        set(Calendar.MINUTE, 30)
        set(Calendar.SECOND, 0)
    }

    val timeInMillis = calendar.timeInMillis

    init {
        viewModelScope.launch {
            repository.getAllReminders().collect { reminders ->
                _state.value = _state.value.copy(reminders = reminders)
            }
        }
    }

    fun saveReminder(
        task: String,
        time: String,
        repeatType: String,
        taskType: String,
        description: String,
        priority: String,
        context: Context
    ){
        val calendar = Calendar.getInstance().apply {
            // Parse time, assume "HH:MM"
            val parts = time.split(":")
            if (parts.size == 2) {
                set(Calendar.HOUR_OF_DAY, parts[0].toIntOrNull() ?: 10)
                set(Calendar.MINUTE, parts[1].toIntOrNull() ?: 30)
            } else {
                set(Calendar.HOUR_OF_DAY, 10)
                set(Calendar.MINUTE, 30)
            }
            set(Calendar.SECOND, 0)
            // If time is in the past, add one day
            if (timeInMillis < System.currentTimeMillis()) {
                add(Calendar.DAY_OF_MONTH, 1)
            }
        }
        val timeInMillis = calendar.timeInMillis

        viewModelScope.launch {
            val reminder  = RemindersEntity(
                task = task,
                time = time,
                repeatType = repeatType,
                taskType = taskType,
                description = description,
                priority = priority
            )
            repository.insertReminder(reminder)
            scheduleRemider(
                context = context,
                timeInMillis = timeInMillis,
                message = "Reminder: $task",
                priority = priority
            )
        }
    }

    fun getAllReminders(){
        viewModelScope.launch {
            repository.getAllReminders()
        }
    }

    fun deleteRemider(task: String){
        viewModelScope.launch {
            repository.deleteReminder(
                RemindersEntity(
                    task = state.value.task
                )
            )
        }
    }

    @SuppressLint("ScheduleExactAlarm")
    suspend fun scheduleRemider(context: Context, timeInMillis: Long, message: String, priority: String){
        val intent = Intent(context, ReceiverReminder::class.java).apply {
            putExtra("message", message)
            putExtra("priority", priority)
        }

        val pendingIntent = PendingIntent.getBroadcast(
            context,
            timeInMillis.toInt(),
            intent,
            PendingIntent.FLAG_IMMUTABLE
        )

        val alarmManager = context.getSystemService(Context.ALARM_SERVICE) as AlarmManager
        alarmManager.setExact(
            AlarmManager.RTC_WAKEUP,
            timeInMillis,
            pendingIntent
        )

    }
}

package com.example.remider.presentation

import android.annotation.SuppressLint
import android.app.AlarmManager
import android.app.PendingIntent
import android.content.Context
import android.content.Intent
import androidx.compose.ui.platform.LocalContext
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.remider.data.RemiderState
import com.example.remider.domain.RemindersEntity
import com.example.remider.domain.RemindersRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import java.util.Calendar
import kotlin.String

class MainViewModel(
    private val repository: RemindersRepository
): ViewModel() {
    private val _state = MutableStateFlow(RemiderState())
    val state = _state.asStateFlow()
    val calendar = Calendar.getInstance().apply {
        set(Calendar.HOUR_OF_DAY, 10)
        set(Calendar.MINUTE, 30)
        set(Calendar.SECOND, 0)
    }

    val timeInMillis = calendar.timeInMillis

    init {
        viewModelScope.launch {
            repository.getAllReminders().collect { reminders ->
                _state.value = _state.value.copy(reminders = reminders)
            }
        }
    }

    fun saveReminder(
        task: String,
        time: String,
        repeatType: String,
        taskType: String,
        description: String,
        priority: String,
        context: Context
    ){
        val calendar = Calendar.getInstance().apply {
            // Parse time, assume "HH:MM"
            val parts = time.split(":")
            if (parts.size == 2) {
                set(Calendar.HOUR_OF_DAY, parts[0].toIntOrNull() ?: 10)
                set(Calendar.MINUTE, parts[1].toIntOrNull() ?: 30)
            } else {
                set(Calendar.HOUR_OF_DAY, 10)
                set(Calendar.MINUTE, 30)
            }
            set(Calendar.SECOND, 0)
        }
        val timeInMillis = calendar.timeInMillis
        // If time is in the past, add one day
        if (timeInMillis < System.currentTimeMillis()) {
            calendar.add(Calendar.DAY_OF_MONTH, 1)
            val newTimeInMillis = calendar.timeInMillis
        }

        viewModelScope.launch {
            val reminder  = RemindersEntity(
                task = task,
                time = time,
                repeatType = repeatType,
                taskType = taskType,
                description = description,
                priority = priority
            )
            repository.insertReminder(reminder)
            scheduleRemider(
                context = context,
                timeInMillis = timeInMillis,
                message = "Reminder: $task",
                priority = priority
            )
        }
    }

    fun getAllReminders(){
        viewModelScope.launch {
            repository.getAllReminders()
        }
    }

    fun deleteRemider(task: String){
        viewModelScope.launch {
            repository.deleteReminder(
                RemindersEntity(
                    task = state.value.task
                )
            )
        }
    }

    @SuppressLint("ScheduleExactAlarm")
    suspend fun scheduleRemider(context: Context, timeInMillis: Long, message: String, priority: String){
        val intent = Intent(context, ReceiverReminder::class.java).apply {
            putExtra("message", message)
            putExtra("priority", priority)
        }

        val pendingIntent = PendingIntent.getBroadcast(
            context,
            timeInMillis.toInt(),
            intent,
            PendingIntent.FLAG_IMMUTABLE
        )

        val alarmManager = context.getSystemService(Context.ALARM_SERVICE) as AlarmManager
        alarmManager.setExact(
            AlarmManager.RTC_WAKEUP,
            timeInMillis,
            pendingIntent
        )

    }
}

package com.example.remider.domain

import androidx.room.Dao
import androidx.room.Delete
import androidx.room.Insert
import androidx.room.Query
import kotlinx.coroutines.flow.Flow

@Dao
interface ReminderDao {

    @Insert
    suspend fun insertReminder(reminder: RemindersEntity)

    @Query("SELECT * FROM reminders")
    suspend fun getAllReminders(): Flow<List<RemindersEntity>>

    @Delete
    suspend fun deleteReminder(reminder: RemindersEntity)
}

package com.example.remider.domain

import androidx.room.Dao
import androidx.room.Delete
import androidx.room.Insert
import androidx.room.Query
import kotlinx.coroutines.flow.Flow

@Dao
interface ReminderDao {

    @Insert
    suspend fun insertReminder(reminder: RemindersEntity)

    @Query("SELECT * FROM reminders")
    fun getAllReminders(): Flow<List<RemindersEntity>>

    @Delete
    suspend fun deleteReminder(reminder: RemindersEntity)
}

